# Let me try the structured logger tool
dotnet tool install --global StructuredLogViewer.Console 2>&1 || dotnet tool install --global MSBuild.StructuredLogger 2>&1 || true
# Alternative: write a quick C# program to read the binlog
cat <<'EOF' > /tmp/read_binlog.csproj
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net8.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.405" />
    <PackageReference Include="Microsoft.Build" Version="17.12.6" ExcludeAssets="runtime" />
    <PackageReference Include="Microsoft.Build.Framework" Version="17.12.6" ExcludeAssets="runtime" />
  </ItemGroup>
</Project>
EOF

cat <<'EOF' > /tmp/read_binlog.cs
using System;
using System.IO;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        Console.WriteLine("=== BUILD RESULT ===");
        Console.WriteLine($"Succeeded: {build.Succeeded}");
        Console.WriteLine();

        // Print all errors
        Console.WriteLine("=== ERRORS ===");
        build.VisitAllChildren<Error>(error => {
            Console.WriteLine($"[{error.ProjectFile}]");
            Console.WriteLine($"  File: {error.File}({error.LineNumber},{error.ColumnNumber})");
            Console.WriteLine($"  Code: {error.Code}");
            Console.WriteLine($"  Message: {error.Message}");
            Console.WriteLine();
        });

        // Print project structure
        Console.WriteLine("=== PROJECTS ===");
        build.VisitAllChildren<Project>(project => {
            Console.WriteLine($"Project: {project.Name} - Succeeded: {project.Succeeded}");
        });

        // Print source file contents from embedded files
        Console.WriteLine();
        Console.WriteLine("=== SOURCE FILES (from binlog) ===");
        var archiveFile = build.SourceFilesArchive;
        if (archiveFile != null)
        {
            Console.WriteLine("Archive found with source files");
            foreach (var file in archiveFile.Children)
            {
                if (file is SourceFile sf)
                {
                    Console.WriteLine($"\n--- {sf.Name} ---");
                    Console.WriteLine(sf.Text?.Substring(0, Math.Min(sf.Text.Length, 5000)));
                }
            }
        }
        else
        {
            Console.WriteLine("No source file archive found in binlog");
        }
    }
}
EOF
