using System;
using System.IO;
using System.IO.Compression;
using System.Linq;
using System.Text;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        Console.WriteLine("=== BUILD RESULT ===");
        Console.WriteLine($"Succeeded: {build.Succeeded}");
        Console.WriteLine();

        // Print all errors
        Console.WriteLine("=== ERRORS ===");
        build.VisitAllChildren<Error>(error => {
            Console.WriteLine($"  Project: {error.ProjectFile}");
            Console.WriteLine($"  File: {error.File}({error.LineNumber},{error.ColumnNumber})");
            Console.WriteLine($"  Code: {error.Code}");
            Console.WriteLine($"  Text: {error.Text}");
            Console.WriteLine();
        });

        // Print project structure and results
        Console.WriteLine("=== PROJECTS ===");
        build.VisitAllChildren<Project>(project => {
            Console.WriteLine($"  Project: {project.Name} | ProjectFile: {project.ProjectFile}");
        });

        // Print source file contents from embedded archive
        Console.WriteLine();
        Console.WriteLine("=== SOURCE FILES (from binlog) ===");
        var archive = build.SourceFilesArchive;
        if (archive != null && archive.Length > 0)
        {
            Console.WriteLine($"Archive size: {archive.Length} bytes");
            using var ms = new MemoryStream(archive);
            using var zip = new ZipArchive(ms, ZipArchiveMode.Read);
            foreach (var entry in zip.Entries)
            {
                Console.WriteLine($"\n--- {entry.FullName} ---");
                using var stream = entry.Open();
                using var reader = new StreamReader(stream);
                var content = reader.ReadToEnd();
                if (content.Length > 8000)
                    Console.WriteLine(content.Substring(0, 8000) + "\n...(truncated)");
                else
                    Console.WriteLine(content);
            }
        }
        else
        {
            Console.WriteLine("No source file archive found in binlog");
        }
    }
}
